sql:
SELECT description
FROM fault_codes
WHERE severity_level = 'Critical';

SELECT location
FROM motor_states
WHERE status = 'Faulty';

SELECT severity_level, COUNT(*) AS fault_count
FROM fault_codes
GROUP BY severity_level;

SELECT COUNT(*) AS faulty_motor_count
FROM motor_states
WHERE status = 'Faulty';

SELECT status
FROM motor_states
WHERE motor_id = 1;

SELECT DISTINCT motor_id
FROM motor_performance_metrics
WHERE temperature > '40';

external_knowledge:
- The severity level 'Critical' implies a high-priority issue; 
- High motor speeds above 1400 RPM, high temperatures above 50 degrees Celsius, and high vibration levels above 0.7 mm/s may indicate impending motor failure; 
- Maintenance actions being taken suggests that these motors have received some form of service or repair; 
- Access through login actions during September 2023 implies that users have logged in to perform these actions.

; A Critical fault is one that requires immediate attention and can cause significant disruption if not addressed promptly; 
; Maintenance department is a group of technicians responsible for ensuring the smooth operation of equipment and machinery; 
; The most recent maintenance refers to the latest maintenance activity performed on a motor.

